html:
{% set inv = doc %}
{%- set company = doc.company
    or frappe.db.get_value("Books Company Member", {"user": frappe.session.user}, "company")
    or frappe.db.get_single_value("Books Settings", "default_company")
    or "Your Company" -%}
{% set company_doc = frappe.get_doc("Company", company) if company and frappe.db.exists("Company", company) else None %}
<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet">
<script src="https://cdnjs.cloudflare.com/ajax/libs/qrcodejs/1.0.0/qrcode.min.js"></script>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    font-family: 'Inter', -apple-system, Arial, sans-serif;
    color: #374151;
    background: #ffffff;
    font-size: 13px;
    line-height: 1.5;
    -webkit-print-color-adjust: exact;
    print-color-adjust: exact;
  }

  .page { max-width: 794px; margin: 0 auto; background: #ffffff; }

  /* RIBBON */
  .ribbon-wrap { position: relative; overflow: hidden; }
  .ribbon {
    position: absolute; top: 26px; right: -36px;
    color: #ffffff;
    font-size: 9px; font-weight: 800; letter-spacing: 1.5px;
    padding: 6px 50px; transform: rotate(45deg);
    text-transform: uppercase; z-index: 20;
    box-shadow: 0 2px 8px rgba(0,0,0,.2);
  }
  .ribbon.paid      { background: #15803D; }
  .ribbon.overdue   { background: #B45309; }
  .ribbon.draft     { background: #6B7280; }
  .ribbon.cancelled { background: #B91C1C; }

  /* TOP STRIPE */
  .top-stripe { height: 6px; background: #1B55E2; }

  /* HEADER */
  .header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    padding: 36px 48px 28px; gap: 32px;
  }
  .logo-area { display: flex; flex-direction: column; gap: 14px; }
  .logo-area img { max-height: 52px; max-width: 176px; object-fit: contain; }
  .logo-placeholder {
    display: flex; align-items: center; justify-content: center;
    width: 138px; height: 50px;
    border: 1.5px dashed #D1D5DB; border-radius: 8px;
    font-size: 10.5px; color: #6B7280;
  }
  .co-name   { font-size: 14px; font-weight: 700; color: #1A1A2E; margin-bottom: 4px; }
  .co-detail { font-size: 11.5px; color: #6B7280; line-height: 1.7; }

  .inv-id { text-align: right; flex-shrink: 0; }
  .doc-chip {
    display: inline-block; background: #1B55E2; color: #ffffff;
    font-size: 8.5px; font-weight: 700; letter-spacing: 2.2px;
    text-transform: uppercase; padding: 4px 14px; border-radius: 20px;
    margin-bottom: 10px;
  }
  .inv-num {
    font-size: 26px; font-weight: 700; color: #0B0F1A;
    letter-spacing: -0.5px; line-height: 1.1; margin-bottom: 14px;
  }
  .meta-table { border-collapse: collapse; margin-left: auto; }
  .meta-table td { padding: 4px 0 4px 20px; font-size: 12px; }
  .meta-table td:first-child { color: #6B7280; font-weight: 400; text-align: left; }
  .meta-table td:last-child  { font-weight: 600; color: #1A1A2E; text-align: right; }

  /* DIVIDER */
  .hdivider { border: none; border-top: 1px solid #F2F4F7; margin: 0 48px; }

  /* PARTIES */
  .parties { display: flex; padding: 24px 48px; gap: 0; }
  .party-col { flex: 1; padding-right: 28px; }
  .party-col + .party-col { padding-left: 28px; padding-right: 0; border-left: 1px solid #F2F4F7; }
  .party-mid {
    flex: 0 0 160px;
    border-left: 1px solid #F2F4F7;
    border-right: 1px solid #F2F4F7;
    padding: 0 24px;
    display: flex; flex-direction: column; align-items: center; gap: 8px;
  }
  .p-tag {
    font-size: 9px; font-weight: 700; letter-spacing: 1.6px;
    text-transform: uppercase; color: #1B55E2; margin-bottom: 5px;
  }
  .p-name   { font-size: 15px; font-weight: 700; color: #0B0F1A; margin-bottom: 4px; }
  .p-detail { font-size: 11.5px; color: #6B7280; line-height: 1.7; }
  .p-gstin  { font-size: 11px; color: #374151; margin-top: 4px; font-weight: 500; }

  /* Status badge */
  .status-badge {
    display: inline-block;
    padding: 5px 13px; border-radius: 20px;
    font-size: 11.5px; font-weight: 600;
  }
  .badge-paid      { background: #DCFCE7; color: #15803D; }
  .badge-overdue   { background: #FEF3C7; color: #B45309; }
  .badge-draft     { background: #F2F4F7; color: #6B7280; }
  .badge-partial   { background: #FEF3C7; color: #B45309; }
  .badge-submitted { background: #EEF3FD; color: #1B55E2; }
  .badge-cancelled { background: #FEE2E2; color: #B91C1C; }

  .currency-pill {
    display: inline-block;
    background: #F8FAFC; border: 1px solid #E5E7EB; border-radius: 20px;
    padding: 4px 14px; font-size: 12px; font-weight: 700; color: #1A1A2E;
  }

  /* ITEMS TABLE */
  .table-wrap { padding: 4px 48px 0; }
  .items-table { width: 100%; border-collapse: collapse; }
  .items-table thead tr { background: #0B0F1A; }
  .items-table thead th {
    padding: 11px 14px;
    font-size: 9.5px; font-weight: 700; letter-spacing: .9px;
    text-transform: uppercase; color: rgba(255,255,255,0.6);
    text-align: left; white-space: nowrap;
  }
  .items-table thead th.tr { text-align: right; }
  .items-table tbody tr { border-bottom: 1px solid #F2F4F7; }
  .items-table tbody tr:nth-child(even) { background: #F8FAFC; }
  .items-table tbody td {
    padding: 13px 14px; font-size: 13px;
    color: #374151; vertical-align: top;
  }
  .items-table td.mono { text-align: right; color: #1A1A2E; }
  .row-idx { color: #D1D5DB; font-size: 11px; }
  .i-name  { font-weight: 600; color: #0B0F1A; }
  .i-desc  { font-size: 11px; color: #6B7280; margin-top: 2px; line-height: 1.5; }
  .i-hsn   { font-size: 10px; color: #D1D5DB; margin-top: 2px; }
  .table-foot { height: 3px; background: #1B55E2; margin-bottom: 24px; }

  /* BOTTOM SECTION */
  .bottom {
    display: flex; padding: 0 48px 32px;
    gap: 24px; align-items: flex-start;
  }
  .notes-col {
    flex: 1; display: flex; flex-direction: column; gap: 12px;
  }
  .card {
    background: #F8FAFC; border: 1px solid #F2F4F7;
    border-radius: 8px; padding: 14px 16px;
  }
  .card-title {
    font-size: 9px; font-weight: 700; letter-spacing: 1.4px;
    text-transform: uppercase; color: #6B7280; margin-bottom: 7px;
  }
  .card p { font-size: 12px; color: #374151; line-height: 1.65; }

  /* QR */
  .qr-col {
    flex: 0 0 148px;
    background: #F8FAFC; border: 1px solid #F2F4F7;
    border-radius: 8px; padding: 14px 12px; text-align: center;
  }
  .qr-col .card-title { margin-bottom: 10px; }
  #qr-canvas { display: flex; justify-content: center; margin-bottom: 8px; }
  .qr-id  { font-size: 9.5px; color: #6B7280; word-break: break-all; }
  .qr-amt { font-size: 11.5px; font-weight: 700; color: #1A1A2E; margin-top: 4px; }

  /* Totals */
  .totals-col { flex: 0 0 260px; }
  .totals-card {
    background: #F8FAFC; border: 1px solid #F2F4F7;
    border-radius: 8px; overflow: hidden;
  }
  .totals-tbl { width: 100%; border-collapse: collapse; }
  .totals-tbl tr + tr td { border-top: 1px solid #F2F4F7; }
  .totals-tbl td { padding: 9px 16px; font-size: 12.5px; }
  .totals-tbl .tl { color: #6B7280; }
  .totals-tbl .tv { text-align: right; font-weight: 500; color: #1A1A2E; }

  .grand td { background: #0B0F1A !important; border-top: none !important; }
  .grand .tl { color: rgba(255,255,255,0.65) !important; font-size: 13.5px; }
  .grand .tv { color: #ffffff !important; font-size: 16px; font-weight: 800; }

  .payment-row .tl, .payment-row .tv { color: #15803D !important; }

  .balance-row td { background: #FEE2E2 !important; border-top: none !important; }
  .balance-row .tl { color: #B91C1C !important; font-weight: 600; }
  .balance-row .tv { color: #B91C1C !important; font-weight: 800; }

  /* E-INVOICE STRIP */
  .einv-strip {
    background: #EEF3FD; border-top: 1px solid #C7D9FC;
    padding: 10px 48px;
    display: flex; gap: 32px; font-size: 10.5px; flex-wrap: wrap;
  }
  .ev { font-weight: 600; color: #1B55E2; word-break: break-all; }
  .el { color: #6B7280; margin-right: 4px; }

  /* FOOTER */
  .footer {
    display: flex; justify-content: space-between; align-items: flex-end;
    padding: 20px 48px 32px;
    border-top: 1px solid #F2F4F7;
  }
  .thank     { font-size: 14.5px; font-weight: 700; color: #0B0F1A; }
  .thank-sub { font-size: 11.5px; color: #6B7280; margin-top: 3px; }
  .sig-block { text-align: center; }
  .sig-line  { width: 160px; border-top: 1.5px solid #D1D5DB; margin: 0 auto 7px; padding-top: 8px; }
  .sig-label { font-size: 10.5px; color: #6B7280; letter-spacing: .4px; }

  @media print {
    .page { max-width: 100%; }
    body  { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
  }
</style>
</head>
<body>
<div class="page ribbon-wrap">

  <!-- Ribbon -->
  {% if inv.status == "Paid" %}
  <div class="ribbon paid">Paid</div>
  {% elif inv.status == "Overdue" %}
  <div class="ribbon overdue">Overdue</div>
  {% elif inv.status == "Draft" %}
  <div class="ribbon draft">Draft</div>
  {% elif inv.status == "Cancelled" %}
  <div class="ribbon cancelled">Cancelled</div>
  {% endif %}

  <div class="top-stripe"></div>

  <!-- HEADER -->
  <div class="header">
    <div class="logo-area">
      {% set logo_url = inv.logo if inv.logo else (company_doc.company_logo if company_doc and company_doc.company_logo else None) %}
      {% if logo_url %}
        <img src="{{ logo_url }}" alt="{{ company }}">
      {% else %}
        <div class="logo-placeholder">Your Logo</div>
      {% endif %}
      <div>
        <div class="co-name">{{ company }}</div>
        <div class="co-detail">
          {% if company_doc %}
            {{ company_doc.address or "" }}{% if company_doc.city %}<br>{{ company_doc.city }}{% if company_doc.country %}, {{ company_doc.country }}{% endif %}{% endif %}
            {% if company_doc.tax_id %}<br><strong style="color:#374151">GSTIN:</strong> {{ company_doc.tax_id }}{% endif %}
          {% endif %}
        </div>
      </div>
    </div>

    <div class="inv-id">
      <div class="doc-chip">Tax Invoice</div>
      <div class="inv-num">{{ inv.name }}</div>
      <table class="meta-table">
        <tr><td>Invoice Date</td><td>{{ frappe.format(inv.posting_date, "Date") }}</td></tr>
        <tr><td>Due Date</td><td>{{ frappe.format(inv.due_date, "Date") }}</td></tr>
        <tr><td>Terms</td><td>{{ inv.payment_terms or "Due on Receipt" }}</td></tr>
        {% if inv.po_no %}
        <tr><td>P.O. #</td><td>{{ inv.po_no }}</td></tr>
        {% endif %}
      </table>
    </div>
  </div>

  <hr class="hdivider">

  <!-- PARTIES -->
  <div class="parties">
    <div class="party-col">
      <div class="p-tag">Bill To</div>
      <div class="p-name">{{ inv.customer_name or inv.customer }}</div>
      <div class="p-detail">
        {{ inv.billing_address | replace("\n", "<br>") if inv.billing_address else "" }}
      </div>
      {% if inv.customer_gstin %}
      <div class="p-gstin">GSTIN: {{ inv.customer_gstin }}</div>
      {% endif %}
    </div>

    <div class="party-mid">
      <div>
        <div class="p-tag" style="text-align:center;letter-spacing:.8px">Status</div>
        {% set smap = {"Paid":"badge-paid","Overdue":"badge-overdue","Draft":"badge-draft","Partly Paid":"badge-partial","Submitted":"badge-submitted","Cancelled":"badge-cancelled"} %}
        <span class="status-badge {{ smap.get(inv.status, 'badge-draft') }}">{{ inv.status }}</span>
      </div>
      <div style="height:10px"></div>
      <div>
        <div class="p-tag" style="text-align:center;letter-spacing:.8px">Currency</div>
        <span class="currency-pill">{{ inv.currency or "INR" }}</span>
      </div>
    </div>

    <div class="party-col" style="padding-left:28px; padding-right:0; text-align:right;">
      <div class="p-tag">Ship To</div>
      {% if inv.shipping_address and inv.shipping_address != inv.billing_address %}
        <div class="p-detail">{{ inv.shipping_address | replace("\n", "<br>") }}</div>
      {% else %}
        <div class="p-name">{{ inv.customer_name or inv.customer }}</div>
        <div class="p-detail" style="color:#D1D5DB;font-style:italic">Same as billing address</div>
      {% endif %}
      {% if inv.place_of_supply %}
      <div class="p-gstin" style="margin-top:8px">Place of Supply: {{ inv.place_of_supply }}</div>
      {% endif %}
    </div>
  </div>

  <hr class="hdivider" style="margin-bottom:4px">

  <!-- ITEMS TABLE -->
  <div class="table-wrap">
    <table class="items-table">
      <thead>
        <tr>
          <th style="width:36px">#</th>
          <th>Item &amp; Description</th>
          <th class="tr" style="width:75px">HSN/SAC</th>
          <th class="tr" style="width:75px">Qty</th>
          <th class="tr" style="width:110px">Rate</th>
          <th class="tr" style="width:50px">Disc%</th>
          <th class="tr" style="width:120px">Amount</th>
        </tr>
      </thead>
      <tbody>
        {% for item in inv.items %}
        <tr>
          <td><span class="row-idx">{{ loop.index }}</span></td>
          <td>
            <div class="i-name">{{ item.item_name }}</div>
            {% if item.description and item.description != item.item_name %}
              <div class="i-desc">{{ item.description }}</div>
            {% endif %}
            {% if item.hsn_code %}<div class="i-hsn">HSN: {{ item.hsn_code }}</div>{% endif %}
          </td>
          <td class="mono">{{ item.hsn_code or "" }}</td>
          <td class="mono">{{ item.qty }}&nbsp;<span style="font-size:10px;color:#6B7280">{{ item.uom or "" }}</span></td>
          <td class="mono">{{ frappe.format(item.rate, "Currency") }}</td>
          <td class="mono">{{ item.discount_percentage if item.discount_percentage else "—" }}</td>
          <td class="mono" style="font-weight:700">{{ frappe.format(item.amount, "Currency") }}</td>
        </tr>
        {% endfor %}
      </tbody>
    </table>
    <div class="table-foot"></div>
  </div>

  <!-- BOTTOM -->
  <div class="bottom">

    <div class="notes-col">
      {% if inv.terms %}
      <div class="card">
        <div class="card-title">Notes &amp; Terms</div>
        <p>{{ inv.terms }}</p>
      </div>
      {% endif %}
      {% if inv.remarks %}
      <div class="card">
        <div class="card-title">Remarks</div>
        <p>{{ inv.remarks }}</p>
      </div>
      {% endif %}
    </div>

    <div class="qr-col">
      <div class="card-title">Pay via UPI</div>
      <div id="qr-canvas"></div>
      <div class="qr-id" id="upi-id-display">
        {{ company_doc.custom_upi_id if company_doc and company_doc.get("custom_upi_id") else "yourupi@bank" }}
      </div>
      <div class="qr-amt">{{ frappe.format(inv.outstanding_amount or inv.grand_total, "Currency") }}</div>
    </div>

    <div class="totals-col">
      <div class="totals-card">
        <table class="totals-tbl">
          <tr><td class="tl">Sub Total</td><td class="tv">{{ frappe.format(inv.net_total, "Currency") }}</td></tr>
          {% for tax in inv.taxes %}
          <tr><td class="tl">{{ tax.description }} ({{ tax.rate }}%)</td><td class="tv">{{ frappe.format(tax.tax_amount, "Currency") }}</td></tr>
          {% endfor %}
          <tr class="grand"><td class="tl">Grand Total</td><td class="tv">{{ frappe.format(inv.grand_total, "Currency") }}</td></tr>
          {% if inv.outstanding_amount and inv.outstanding_amount < inv.grand_total %}
          <tr class="payment-row"><td class="tl">Payment Made</td><td class="tv">(&#8211;) {{ frappe.format((inv.grand_total - inv.outstanding_amount), "Currency") }}</td></tr>
          {% endif %}
          {% if inv.outstanding_amount and inv.outstanding_amount > 0 %}
          <tr class="balance-row"><td class="tl">Balance Due</td><td class="tv">{{ frappe.format(inv.outstanding_amount, "Currency") }}</td></tr>
          {% endif %}
        </table>
      </div>
    </div>

  </div>

  <!-- E-INVOICE STRIP -->
  {% if inv.irn %}
  <div class="einv-strip">
    <span><span class="el">IRN:</span><span class="ev">{{ inv.irn }}</span></span>
    {% if inv.ack_no %}<span><span class="el">ACK No:</span><span class="ev">{{ inv.ack_no }}</span></span>{% endif %}
    {% if inv.ack_date %}<span><span class="el">ACK Date:</span><span class="ev">{{ frappe.format(inv.ack_date, "Date") }}</span></span>{% endif %}
  </div>
  {% endif %}

  <!-- FOOTER -->
  <div class="footer">
    <div>
      <div class="thank">Thank you for your business.</div>
      <div class="thank-sub">We appreciate your prompt payment.</div>
    </div>
    <div class="sig-block">
      <div class="sig-line"></div>
      <div class="sig-label">Authorized Signatory</div>
    </div>
  </div>

</div>

<script>
(function(){
  try{
    var upiId=document.getElementById("upi-id-display").textContent.trim();
    var amtEl=document.querySelector(".qr-amt");
    var amt=amtEl?amtEl.textContent.replace(/[^0-9.]/g,"").trim():"0";
    var co={{ company | tojson }};
    var inv={{ inv.name | tojson }};
    var str="upi://pay?pa="+encodeURIComponent(upiId)+"&pn="+encodeURIComponent(co)+"&am="+encodeURIComponent(amt)+"&cu=INR&tn="+encodeURIComponent("Payment for "+inv);
    new QRCode(document.getElementById("qr-canvas"),{text:str,width:108,height:108,colorDark:"#0B0F1A",colorLight:"#F8FAFC",correctLevel:QRCode.CorrectLevel.M});
  }catch(e){
    var c=document.getElementById("qr-canvas");
    if(c)c.innerHTML='<div style="width:108px;height:108px;display:flex;align-items:center;justify-content:center;font-size:9px;color:#9AA0AB;border:1px dashed #ccc;border-radius:4px">QR n/a</div>';
  }
})();
</script>

</body>
</html>
